/**
 * Material Symbols Subset Generator
 *
 * Reads list of icons used in the theme, extracts their Unicode codepoints
 * from the official Google CodePoints file, and uses `subset-font` to produce
 * a tiny WOFF2 with only those icons.
 *
 * Inputs:
 *   - /tmp/icons-used.txt           (one icon name per line, generated by audit script)
 *   - /tmp/material-symbols.codepoints (Google's codepoint map: "icon_name HEX")
 *   - /tmp/material-symbols.woff2   (full variable font, 3.83 MB)
 *
 * Output:
 *   - assets/fonts/material-symbols-subset.woff2
 *
 * Run from theme root:
 *   node scripts/subset-material-symbols.js
 */

const fs = require('fs');
const path = require('path');
const subsetFont = require('subset-font');

async function main() {
    const iconsListPath = '/tmp/icons-used.txt';
    const codepointsPath = '/tmp/material-symbols.codepoints';
    const fontInputPath = '/tmp/material-symbols.woff2';
    const outputPath = path.join(__dirname, '..', 'assets', 'fonts', 'material-symbols-subset.woff2');

    // Verify inputs exist
    for (const f of [iconsListPath, codepointsPath, fontInputPath]) {
        if (!fs.existsSync(f)) {
            console.error(`❌ Missing input: ${f}`);
            process.exit(1);
        }
    }

    // Read icon names we use
    const usedIcons = fs.readFileSync(iconsListPath, 'utf8')
        .split('\n')
        .map(s => s.trim())
        .filter(Boolean);

    console.log(`📋 Icons to include: ${usedIcons.length}`);

    // Build codepoints map: icon_name → hex_codepoint
    const codepointMap = {};
    fs.readFileSync(codepointsPath, 'utf8')
        .split('\n')
        .forEach(line => {
            const [name, hex] = line.trim().split(/\s+/);
            if (name && hex) codepointMap[name] = hex;
        });

    console.log(`📚 Codepoints map: ${Object.keys(codepointMap).length} icons`);

    // Look up codepoints for our icons
    const codepoints = [];
    const missing = [];
    for (const icon of usedIcons) {
        if (codepointMap[icon]) {
            codepoints.push(codepointMap[icon]);
        } else {
            missing.push(icon);
        }
    }

    if (missing.length > 0) {
        console.warn(`⚠️  ${missing.length} icons not in Google's codepoints map:`);
        missing.forEach(i => console.warn(`     ${i}`));
    }

    console.log(`✅ Resolved ${codepoints.length} codepoints`);

    // Convert hex codepoints to actual Unicode characters
    // (subset-font expects a string of characters, not codepoints)
    const characters = codepoints
        .map(hex => String.fromCodePoint(parseInt(hex, 16)))
        .join('');

    // ALSO include the icon name characters (for ligature lookup table to work)
    // Material Symbols renders icon NAMES via ligatures — when you write "home" in HTML,
    // the font's ligature table maps h+o+m+e → glyph for home icon.
    // So we need to keep all the basic Latin lowercase + underscore characters used in icon names.
    const nameChars = new Set();
    usedIcons.forEach(icon => {
        for (const c of icon) nameChars.add(c);
    });
    const allCharsToKeep = characters + Array.from(nameChars).join('');

    console.log(`🔤 Characters to subset: ${allCharsToKeep.length} (icons: ${codepoints.length}, name chars: ${nameChars.size})`);

    // Read input font
    const inputBuffer = fs.readFileSync(fontInputPath);
    const sizeBefore = inputBuffer.length;

    // Generate subset (preserves variable axes)
    const subsetBuffer = await subsetFont(inputBuffer, allCharsToKeep, {
        targetFormat: 'woff2',
        // Preserve OpenType features needed for ligatures (icon name → glyph)
        preserveNameIds: [],
    });

    const sizeAfter = subsetBuffer.length;

    // Ensure output directory exists
    fs.mkdirSync(path.dirname(outputPath), { recursive: true });

    // Write output
    fs.writeFileSync(outputPath, subsetBuffer);

    // Report
    console.log('');
    console.log('='.repeat(60));
    console.log(`✅ Subset font written: ${outputPath}`);
    console.log(`   Original: ${sizeBefore.toLocaleString()} bytes (${(sizeBefore/1024).toFixed(1)} KB)`);
    console.log(`   Subset:   ${sizeAfter.toLocaleString()} bytes (${(sizeAfter/1024).toFixed(1)} KB)`);
    console.log(`   Reduction: ${((1 - sizeAfter/sizeBefore) * 100).toFixed(1)}%`);
    console.log('='.repeat(60));
}

main().catch(err => {
    console.error('❌ Subset failed:', err);
    process.exit(1);
});
